UPDATE PRODUCTS
SET PRODUCT_NAME  = #{productName},
    PRODUCT_PRICE = #{productPrice, jdbcType=NUMERIC},
    TRADE_STATUS  = #{tradeStatus},
    PRODUCT_DESC  = #{productDesc, jdbcType=VARCHAR}
WHERE PRODUCT_NO   = #{productNo}
  AND SELLER_EMAIL = #{email}

mapper.delete:
DELETE FROM PRODUCTS
WHERE PRODUCT_NO   = #{productNo}
  AND SELLER_EMAIL = #{email}

mapper.update:
UPDATE ACCOUNTS
SET BANK_NAME      = #{bankName},
    ACCOUNT_NUM    = #{accountNum},
    ACCOUNT_HOLDER = #{accountHolder}
WHERE ACCOUNT_ID = #{accountId} AND EMAIL = #{email}

UPDATE ACCOUNTS
SET IS_PRIMARY = CASE WHEN ACCOUNT_ID = #{accountId} THEN 'Y' ELSE 'N' END
WHERE EMAIL = #{email}

UPDATE DELIVERY_ADDRESS
SET IS_PRIMARY = CASE WHEN DELIVERY_NO = #{deliveryNo} THEN 'Y' ELSE 'N' END
WHERE MEMBER_EMAIL = #{email}
